#include<bits/stdc++.h>
using namespace std;
#define endl '\n'
const int maxn=1e3+5, kd[][2]={1,0,0,1,-1,0,0,-1};
int n, m, sx, sy, ex, ey, d[maxn][maxn];
char a[maxn][maxn];
struct node {
    int x, y, data;
};
deque<node> q;

int main() {
    ios::sync_with_stdio(0), cin.tie(0), cout.tie(0);
    cin >> n >> m >> sx >> sy >> ex >> ey;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            cin >> a[i][j];  // 使用 cin 读取字符
            d[i][j] = -1;
        }
    }

    q.push_front({sx, sy, 0});
    while (!q.empty()) {
        node u = q.front();
        q.pop_front();
        int x = u.x, y = u.y, data = u.data;

        if (x >= 1 && x <= n && y >= 1 && y <= m && d[x][y] == -1 && a[x][y] == '.') {
            d[x][y] = data;
            for (int i = 0; i < 4; i++) {
                int nx = x + kd[i][0], ny = y + kd[i][1];
                if (nx >= 1 && nx <= n && ny >= 1 && ny <= m) {
                    q.push_front({nx, ny, data});
                }
            }
            for (int i = -2; i <= 2; i++) {
                for (int j = -2; j <= 2; j++) {
                    if (i == 0 && j == 0) continue;
                    int nx = x + i, ny = y + j;
                    if (nx >= 1 && nx <= n && ny >= 1 && ny <= m) {
                        q.push_back({nx, ny, data + 1});
                    }
                }
            }
        }
    }
    cout << d[ex][ey];
    return 0;
}
